/**
 * @fileoverview Standardised Custom Event dispatcher for RazyUI components.
 *
 * All component events use `{ bubbles: true, composed: true }` so they
 * cross shadow-DOM boundaries.  Event names are prefixed with `rui-`.
 *
 * @module shared/emitEvent
 */

/**
 * Dispatch a prefixed custom event from an element.
 *
 * @param {Element} el   — DOM element to dispatch from
 * @param {string}  name — event name WITHOUT `rui-` prefix (e.g. 'change')
 * @param {*}  [detail={}] — event detail payload
 * @returns {boolean} `false` if `preventDefault()` was called
 */
export function emitEvent(el, name, detail = {}) {
    return el.dispatchEvent(new CustomEvent(`rui-${name}`, {
        bubbles: true,
        composed: true,
        cancelable: true,
        detail,
    }));
}
